module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output mul_out
);
output reg mul_en_out_reg;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_en_out_reg <= 0;
    end else begin
        mul_en_out_reg <= mul_en_in;
    end
end
assign mul_en_out = mul_en_out_reg[7];
reg [7:0] mul_a_reg;
reg [7:0] mul_b_reg;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= 0;
        mul_b_reg <= 0;
    end else begin
        if (mul_en_in) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
        end
    end
end
wire [7:0] temp[7:0];
genvar i;
generate
    for (i = 0; i < 8; i = i + 1) begin : gen_partial_products
        assign temp[i] = mul_a_reg & {8{mul_b_reg[i]}};
    end
endgenerate
reg [15:0] partial_sum[7:0];
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        partial_sum[0] <= 0;
        partial_sum[1] <= 0;
        partial_sum[2] <= 0;
        partial_sum[3] <= 0;
        partial_sum[4] <= 0;
        partial_sum[5] <= 0;
        partial_sum[6] <= 0;
        partial_sum[7] <= 0;
    end else begin
        partial_sum[0] <= temp[0];
        partial_sum[1] <= temp[1] + temp[2];
        partial_sum[2] <= temp[3] + temp[4];
        partial_sum[3] <= temp[5] + temp[6];
        partial_sum[4] <= temp[7];
        partial_sum[5] <= temp[3] + temp[4];
        partial_sum[6] <= temp[5] + temp[6];
        partial_sum[7] <= temp[7];
    end
end
assign mul_out = mul_en_out_reg ? (partial_sum[7] + partial_sum[6]) : 0;
endmodule
